SELECT

FROM activity_info

  deleted = 0

    AND activity_id = #{activityId, jdbcType=VARCHAR}


    AND activity_name LIKE CONCAT('%', #{activityName, jdbcType=VARCHAR}, '%')


    AND status = #{status, jdbcType=VARCHAR}


    AND created_time >= #{startTime, jdbcType=TIMESTAMP}


    AND created_time <= #{endTime, jdbcType=TIMESTAMP}



  ORDER BY ${orderBy} 


  LIMIT #{limit, jdbcType=INTEGER}


  OFFSET #{offset, jdbcType=INTEGER}

SELECT COUNT(1)
FROM activity_info

  deleted = 0

    AND activity_id = #{activityId, jdbcType=VARCHAR}


    AND activity_name LIKE CONCAT('%', #{activityName, jdbcType=VARCHAR}, '%')


    AND status = #{status, jdbcType=VARCHAR}


    AND created_time >= #{startTime, jdbcType=TIMESTAMP}


    AND created_time <= #{endTime, jdbcType=TIMESTAMP}

SELECT

FROM activity_info
WHERE status = #{status, jdbcType=VARCHAR}
  AND created_time BETWEEN #{startTime, jdbcType=TIMESTAMP} AND #{endTime, jdbcType=TIMESTAMP}
  AND deleted = 0
ORDER BY created_time DESC
LIMIT #{limit, jdbcType=INTEGER}
